def next_permutation(xs):
    def swap(i, j):
        xs[i], xs[j] = xs[j], xs[i]

    def reverse(start):
        left, right = start, len(xs) - 1
        while left < right:
            swap(left, right)
            left += 1
            right -= 1

    i = len(xs) - 2
    while i >= 0 and xs[i] >= xs[i + 1]:
        i -= 1
    if i < 0:
        reverse(0)
    else:
        j = len(xs) - 1
        while xs[j] <= xs[i]:
            j -= 1
        swap(i, j)
        reverse(i + 1)
